INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-f7485f85-moex-00071', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X1年底原料存貨成本為$60,000，該原料用於生產A產品，需再投入加工成本$20,000 才能出售。X1年底該原料之市場價格已跌至$57,000，估計因原料下跌將使A產品售價降為 $90,000，銷售費用為售價的10%。若該原料X0年底時無減損，甲公司X1年該原料應認列 之存貨跌價損失為何？', '["$0", "$1,000", "$3,000", "$10,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00072', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司於X0年1月1日以$769,228取得乙公司5年期之公司債，甲公司持有該債券之經營 模式目的係收取合約現金流量。該債券面額為$800,000、票面利率9%、每年7月1日與1月 1日付息，有效利率為10%。若甲公司因有資金需求，於X0年底以$770,000加計應計利息出 售持有之全部乙公司債券，則該債券之處分損益為？（四捨五入至整數）', '["損失$4,273", "損失$3,426", "利得$1,396", "利得$772"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00073', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '下列關於預期信用損失之敘述，何者錯誤？', '["評估金融資產減損資訊，須考量未來可能導致債務人信用違約的前瞻性資訊", "因為金融資產減損係採預期信用損失模式，即使在財務報導日用公允價值買入之金融資產， 當日亦得認列減損損失", "若金融資產於報導日之信用風險相較原始認列時沒有顯著增加，應認列未來 12 個月預期 信用損失；而「未來12個月預期信用損失」是指評估日後未來12個月內債務人違約，導 致債權人在未來12個月少收回現金流量的損失", "預期信用損失模式適用按攤銷後成本衡量與透過其他綜合損益按公允價值衡量之債券投 資；然而透過損益按公允價值衡量之債券投資，因報導日公允價值之變動列入當期損益， 則不用再評估預期信用損失"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00074', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '丁公司於X1年1月1日投資每單位面額$1,000之甲公司公司債，共投資1,000單位。債券到 期日為X6年1月1日、票面利率10%、每年1月1日付息一次，且本金於到期日一次清償。 債券投資人要求報酬率為12%，且丁公司投資甲公司債券之目的為持有至到期日。關於丁公', '["丁公司將此債券投資分類為按攤銷後成本衡量之金融資產", "丁公司於債券持有5年間，每年因多拿2%報酬率之利息，故投資金額超過面額$1,000,000", "丁公司於X1年1月1日購買該債券投資，後續只要收取5次現金利息與到期日收回面額 $1,000,000，將可實現要求報酬率 12%", "於債券存續期間 5 年，當市場利率上漲且大於票 面利率10%時，丁公司將有誘因提前出售該債券  ⑤於債券存續期間5年，當市場利率走跌 且小於發行時市場利率12%時，甲公司將有誘因提前向丁公司贖回該債券"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00075', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', 'X5年4月1日甲公司以$15,000出售一台機器設備。出售之機器係於X1年1月1日購入， 原始成本$40,000，估計耐用年限10年、殘值$6,000。甲公司後續衡量採成本模式並以雙倍餘 額遞減法提列折舊。該機器設備應認列之處分資產損失為：（答案四捨五入至元）', '["$565", "$696", "$819", "$4,230"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00076', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', 'X1年5月1日甲公司與乙公司交換非貨幣性資產，其資料如下： 甲公司 乙公司 原始成本 $70,000 $65,000 累計折舊（至交換日） $22,000 $16,000 交換日公允價值 $45,000 $50,000 現金收（付） $ (5,000) $ 5,000 倘若交換交易不具有商業實質，則乙公司換入資產之入帳金額為：', '["$44,000", "$45,000", "$50,000", "$51,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00077', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '下列有關投資性不動產之敘述，何者正確？', '["飯店業者購入一棟建築物，為供顧客住宿服務使用，該建築物屬投資性不動產", "認列後之衡量模式有二種：成本模式與公允價值模式", "無論採用何種衡量模式，一律均需提列折舊費用", "選擇成本模式衡量投資性不動產時，可不揭露其投資性不動產之公允價值"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00078', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X1年初以$120購買生物資產，並另支付$12運回公司；若此時出售該生物資產，將 須花費$15運至同一市場出售。X1年飼養支出$16，X1年底該生物資產公允價值減出售成本 為$125。假設甲公司以公允價值衡量該生物資產，下列敘述何者正確？（不考慮所得稅影響）', '["X1年初以$132認列生物資產", "X1年飼養支出$16，只能資本化以增加生物資產價值", "X1年底記錄該生物資產之公允價值變動時，產生$5的公允價值變動利益", "X1年該生物資產對當期損益之影響為淨損失$23"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00079', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司成立於X1年初，X1年度出售足球框5,000件，每件售價為$30,000，均附有1年期的 保證型保固。依據該公司經驗，估計5%在1年保固內會發生損壞，每件的修理費平均為$20。 X1年實際發生的產品保固支出為$2,800，則X1年底調整後試算表中足球框產品保固費用與 產品保固負債準備之金額分別為何？', '["$5,000，$2,200", "$2,200，$5,000", "$5,000，$2,800", "$2,800，$5,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00080', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司經營一處近海油田，依據授權協議，甲公司於生產完成後應移除油井設備並恢復海床。 最終成本之90%係與移除油井設備及恢復因建構設備所造成之損害有關，剩餘之10%則因採 油而發生。於X5年報導期間結束日，油井設備已建置完成，但尚未開採出石油。試問：甲公 司應於X5年底之資產負債表認列多少因上述事件所產生之負債準備？', '["由於損失與未來營運有關，故不得認列負債準備", "由於負債準備之發生具存在不確定性，故僅能附註揭露", "應按最終成本之90%認列為負債準備", "應按最終成本全額認列為負債準備 61050"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL)
